import java.util.*;
import java.util.stream.*;
public class GroupDemo {
    public static void main(String[] args) {
        List<String> words = List.of("cat", "car", "bat", "bar", "cap");

        Map<Character, List<String>> byFirst = words.stream()
            .collect(Collectors.groupingBy(w -> w.charAt(0)));

        List<String> cWords = new ArrayList<>(byFirst.get('c'));
        Collections.sort(cWords);
        System.out.println(cWords);
        System.out.println(byFirst.get('b').size());
    }
}
